NS="karma-rabbitmq-day2-marathon-01-20260-147890ff-cluster-a"
# Get current erlang cookie and admin pass for the definitions
ADMIN_PASS=$(kubectl -n $NS get secret rabbitmq-admin -o jsonpath='{.data.password}' | base64 -d)

# Build the definitions JSON
cat <<EOF
{
  "rabbitmq_version": "4.1.8",
  "users": [
    {"name":"admin","password_hash":"","hashing_algorithm":"rabbit_password_hashing_sha256","tags":"administrator","limits":{}},
    {"name":"app-user","password_hash":"","hashing_algorithm":"rabbit_password_hashing_sha256","tags":"management","limits":{}},
    {"name":"ops-user","password_hash":"","hashing_algorithm":"rabbit_password_hashing_sha256","tags":"management","limits":{}}
  ],
  "vhosts": [
    {"name":"/"},
    {"name":"/app"},
    {"name":"/ops"}
  ],
  "permissions": [
    {"user":"admin","vhost":"/","configure":".*","write":".*","read":".*"},
    {"user":"admin","vhost":"/app","configure":".*","write":".*","read":".*"},
    {"user":"admin","vhost":"/ops","configure":".*","write":".*","read":".*"},
    {"user":"app-user","vhost":"/app","configure":"","write":".*","read":".*"},
    {"user":"ops-user","vhost":"/app","configure":".*","write":".*","read":".*"}
  ],
  "queues": [
    {"name":"app-queue","vhost":"/app","durable":true,"auto_delete":false,"arguments":{"x-queue-type":"quorum"}},
    {"name":"ops-queue","vhost":"/ops","durable":true,"auto_delete":false,"arguments":{"x-queue-type":"quorum"}}
  ],
  "exchanges": [],
  "bindings": []
}
EOF

