input.command:
NS="karma-rabbitmq-day2-marathon-01-20260-147890ff-cluster-a"
# Update enabled_plugins: remove rabbitmq_peer_discovery_k8s since we're using classic config now
kubectl -n $NS patch configmap rabbitmq-config --type merge -p '{
  "data": {
    "enabled_plugins": "[rabbitmq_management,rabbitmq_prometheus].\n"
  }
}' 2>&1

NS="karma-rabbitmq-day2-marathon-01-20260-147890ff-cluster-a"
# Patch StatefulSet to add volumeMount for definitions.json
kubectl -n $NS patch statefulset rabbitmq --type=json -p='[
  {
    "op": "add",
    "path": "/spec/template/spec/containers/0/volumeMounts/-",
    "value": {
      "name": "config",
      "mountPath": "/etc/rabbitmq/definitions.json",
      "subPath": "definitions.json"
    }
  }
]' 2>&1
